from flask import Flask, request, jsonify
import os
import json
import time
from threading import Lock

app = Flask(__name__)

CACHE_DIR = 'cache'
CACHE_EXPIRATION = 3600  # 1 hour
cache_lock = Lock()

def get_cache_file_path(key):
    return os.path.join(CACHE_DIR, f"{key}.json")

def load_cache(key):
    cache_file = get_cache_file_path(key)
    if os.path.exists(cache_file):
        with open(cache_file, 'r') as f:
            data = json.load(f)
            if time.time() - data['timestamp'] < CACHE_EXPIRATION:
                return data['response']
    return None

def save_cache(key, response):
    cache_file = get_cache_file_path(key)
    with open(cache_file, 'w') as f:
        json.dump({'timestamp': time.time(), 'response': response}, f)

@app.route('/expensive-api', methods=['GET'])
def expensive_api():
    key = request.args.get('key')
    with cache_lock:
        cached_response = load_cache(key)
        if cached_response is not None:
            return jsonify(cached_response)

    # Simulate an expensive API call
    response = {'data': 'Expensive API response', 'key': key}
    
    with cache_lock:
        save_cache(key, response)
    
    return jsonify(response)

if __name__ == '__main__':
    if not os.path.exists(CACHE_DIR):
        os.makedirs(CACHE_DIR)
    app.run(debug=True)